### 3. REGISTRY AND COMMAND TYPES

**Path:** `/Users/anotonio.silva/antonio/lol/src/registry/types.ts`

```typescript
import type { ComponentType, ReactNode } from 'react';
import type { ListItemAccessoryData, ListItemDetailData } from '../types';

export type CommandMode = 'view' | 'no-view' | 'menu-bar';

export interface ExtensionCommand {
  name: string;
  title: string;
  subtitle?: string;
  icon: ReactNode;
  keywords?: string[];
  aliases?: string[];
  mode: CommandMode;
  component?: ComponentType;
  fullView?: boolean;
  section?: string;
  accessories?: ListItemAccessoryData[];
  detail?: ListItemDetailData;
}

export interface ExtensionManifest {
  id: string;
  name: string;
  icon: ReactNode;
  description: string;
  author: string;
  commands: ExtensionCommand[];
}

export interface CommandRegistration {
  id: string;
  name: string;
  subtitle?: string;
  icon: ReactNode;
  keywords?: string[];
  aliases?: string[];
  section: string;
  accessories?: ListItemAccessoryData[];
  detail?: ListItemDetailData;
  component?: ComponentType;
  fullView?: boolean;
  extensionId?: string;
}
```

**How command registry works:**
```typescript
// Path: src/registry/command_registry.ts
export function registerExtension(manifest: ExtensionManifest): void {
  for (const cmd of manifest.commands) {
    const section = cmd.section ?? manifest.name;
    registerCommand({
      id: cmd.name,
      name: cmd.title,
      subtitle: cmd.subtitle,
      icon: cmd.icon,
      keywords: cmd.keywords,
      aliases: cmd.aliases,
      section,
      accessories: cmd.accessories,
      detail: cmd.detail,
      component: cmd.component,
      fullView: cmd.fullView,
      extensionId: manifest.id,
    });
  }
}
```

