### 7. COMPONENT COMPOSITION PATTERN

**Translator Layout Structure (Two-Panel):**

```typescript
// For web demo mode with mock translation:
function SimpleTranslatorView() {
  const [sourceText, setSourceText] = useState('');
  const [sourceLang, setSourceLang] = useState('en');
  const [targetLang, setTargetLang] = useState('es');

  // Mock translation function
  const translatedText = useMemo(() => {
    return sourceText.split('').reverse().join(''); // Simple mock
  }, [sourceText]);

  return (
    <>
      <SearchBar
        value={sourceText}
        onChange={setSourceText}
        placeholder="Enter text to translate..."
      />
      <div className="translator__body">
        <div className="translator__source-panel">
          <select value={sourceLang} onChange={e => setSourceLang(e.target.value)}>
            {SUPPORTED_LANGUAGES.map(lang => (
              <option key={lang.code} value={lang.code}>{lang.name}</option>
            ))}
          </select>
          <textarea
            value={sourceText}
            onChange={e => setSourceText(e.target.value)}
            placeholder="Source text..."
          />
        </div>

        <div className="translator__controls">
          <button onClick={handleSwapLanguages}>⇄ Swap</button>
        </div>

        <div className="translator__target-panel">
          <select value={targetLang} onChange={e => setTargetLang(e.target.value)}>
            {SUPPORTED_LANGUAGES.map(lang => (
              <option key={lang.code} value={lang.code}>{lang.name}</option>
            ))}
          </select>
          <textarea
            value={translatedText}
            readOnly
            placeholder="Translation..."
          />
        </div>
      </div>
      <ActionPanel
        actions={[
          { label: 'Copy', shortcut: <Kbd keys={['⌘', 'C']} /> },
        ]}
      />
      <HUDContainer items={hudItems} />
    </>
  );
}
