127→function rowToEntry(row: NoteRow): NoteEntry {
128→  const createdAt = new Date(row.created_at);
129→  const updatedAt = new Date(row.updated_at);
130→  return {
131→    id: row.id,
132→    title: row.title,
133→    content: row.content,
134→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
135→    updatedAt: isNaN(updatedAt.getTime()) ? new Date() : updatedAt,
136→  };
137→}
138→
139→function entryToRow(entry: NoteEntry): NoteRow {
140→  return {
141→    id: entry.id,
142→    title: entry.title,
143→    content: entry.content,
144→    created_at: entry.createdAt.toISOString(),
145→    updated_at: entry.updatedAt.toISOString(),
146→  };
147→}
