156→function NoteEditorView({ note, onSave }: NoteEditorViewProps) {
157→  const [title, setTitle] = useState(note?.title ?? '');
158→  const [content, setContent] = useState(note?.content ?? '');
159→  const [preview, setPreview] = useState(false);
160→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
161→  const titleRef = useRef(title);
162→  const contentRef = useRef(content);
163→  const onSaveRef = useRef(onSave);
164→
165→  titleRef.current = title;
166→  contentRef.current = content;
167→  onSaveRef.current = onSave;
168→
169→  const debounceSave = useCallback(() => {
170→    if (debounceRef.current) clearTimeout(debounceRef.current);
171→    debounceRef.current = setTimeout(() => {
172→      onSaveRef.current(titleRef.current, contentRef.current);
173→    }, 500);
174→  }, []);
175→
176→  useEffect(() => {
177→    return () => {
178→      if (debounceRef.current) {
179→        clearTimeout(debounceRef.current);
180→        onSaveRef.current(titleRef.current, contentRef.current);
181→      }
182→    };
183→  }, []);
184→
185→  const handleTitleChange = useCallback(
186→    (e: React.ChangeEvent<HTMLInputElement>) => {
187→      setTitle(e.target.value);
188→      debounceSave();
189→    },
190→    [debounceSave],
191→  );
192→
193→  const handleContentChange = useCallback(
194→    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
195→      setContent(e.target.value);
196→      debounceSave();
197→    },
198→    [debounceSave],
199→  );
200→
201→  const handleFlushSave = useCallback(() => {
202→    if (debounceRef.current) clearTimeout(debounceRef.current);
203→    onSaveRef.current(titleRef.current, contentRef.current);
204→  }, []);
205→
206→  const togglePreview = useCallback(() => {
207→    setPreview(prev => !prev);
208→  }, []);
209→
210→  useKeyboardShortcut(
211→    {
212→      key: 's',
213→      meta: true,
214→    },
215→    handleFlushSave,
216→  );
217→  useKeyboardShortcut(
218→    {
219→      key: 'p',
220→      meta: true,
221→      shift: true,
222→    },
223→    togglePreview,
224→  );
225→
226→  const renderedHtml = useMemo(
227→    () =>
228→      preview
229→        ? DOMPurify.sanitize(
230→            marked.parse(content || '*No content*', { async: false }),
231→          )
232→        : '',
233→    [
234→      content,
235→      preview,
236→    ],
237→  );
238→
239→  return (
240→    <div className="notes-editor">
241→      <div className="notes-editor__header">
242→        <input
243→          className="notes-editor__title-input"
244→          type="text"
245→          value={title}
246→          onChange={handleTitleChange}
247→          placeholder="Note Title"
248→          aria-label="Note title"
249→          autoFocus={!preview}
250→          readOnly={preview}
251→        />
252→        <button
253→          className={`notes-editor__preview-toggle${preview ? ' notes-editor__preview-toggle--active' : ''}`}
254→          onClick={togglePreview}
255→          aria-label={
256→            preview ? 'Switch to edit mode' : 'Switch to preview mode'
257→          }
258→          aria-pressed={preview}
259→          type="button"
260→        >
261→          {preview ? 'Edit' : 'Preview'}
262→        </button>
263→      </div>
264→      {preview ? (
265→        <div
266→          className="notes-editor__preview detail__markdown"
267→          dangerouslySetInnerHTML={{ __html: renderedHtml }}
268→          role="document"
269→          aria-label="Markdown preview"
270→        />
271→      ) : (
272→        <textarea
273→          className="notes-editor__content-area"
274→          value={content}
275→          onChange={handleContentChange}
276→          placeholder="Start writing..."
277→          aria-label="Note content"
278→        />
279→      )}
280→      {note && (
281→        <div className="notes-editor__meta">
282→          <span>Modified {note.updatedAt.toLocaleString()}</span>
283→        </div>
284→      )}
285→    </div>
286→  );
