289→export function FloatingNotesView() {
290→  const nav = useNavigation();
291→  const [entries, setEntries] = useState<NoteEntry[]>([]);
292→  const [query, setQuery] = useState('');
293→  const [selectedIndex, setSelectedIndex] = useState(0);
