308→          setEntries(rows.map(rowToEntry));
309→        } else if (!isTauri) {
310→          const mock = MOCK_NOTE_ENTRIES.map(e => ({ ...e }));
311→          setEntries(mock);
312→          Promise.all(mock.map(e => noteDb.insert(entryToRow(e)))).catch(
313→            console.error,
314→          );
315→        }
316→      })
317→      .catch(err => {
318→        console.error('Failed to load notes:', err);
319→        if (!isTauri && !aborted) {
320→          setEntries(MOCK_NOTE_ENTRIES.map(e => ({ ...e })));
321→        }
322→      });
323→
324→    return () => {
325→      aborted = true;
326→    };
327→  }, []);
328→
329→  const dbSearchFn = useCallback((q: string) => noteDb.search(q), []);
330→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
331→    query,
332→    dbSearchFn,
333→    rowToEntry,
334→  );
335→
336→  const filtered = useMemo(() => {
337→    const items = ftsResults ?? entries;
338→    if (!ftsResults && query) {
339→      return items.filter(
340→        e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.content),
