@use '../../styles/tokens';

.translator {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow: hidden;

  &__panels {
    display: flex;
    flex: 1;
    overflow: hidden;
  }

  &__panel {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
  }

  &__panel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: tokens.$space-2 tokens.$space-3;
    border-bottom: 1px solid var(--border-100);
    min-height: 36px;
    gap: tokens.$space-2;
  }

  &__lang-label {
    font-family: tokens.$font-family;
    font-size: tokens.$font-sm;
    font-weight: tokens.$font-weight-medium;
    color: var(--text-600);
    white-space: nowrap;
  }

  &__detected-badge {
    font-size: tokens.$font-xs;
    color: var(--color-accent);
    white-space: nowrap;
  }

  &__textarea {
    flex: 1;
    width: 100%;
    background: transparent;
    border: none;
    outline: none;
    font-family: tokens.$font-family;
    font-size: tokens.$font-base;
    color: var(--color-text-primary);
    resize: none;
    padding: tokens.$space-3;
    line-height: 1.6;
    min-height: 120px;

    &::placeholder {
      color: var(--text-400);
    }
  }

  &__output {
    flex: 1;
    padding: tokens.$space-3;
    font-family: tokens.$font-family;
    font-size: tokens.$font-base;
    color: var(--color-text-primary);
    line-height: 1.6;
    overflow-y: auto;
    user-select: text;
    white-space: pre-wrap;
    word-break: break-word;
  }

  &__output-placeholder {
    color: var(--text-400);
  }

  &__divider {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    border-right: 1px solid var(--border-100);
    position: relative;
  }

  &__swap-button {
    position: absolute;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    background: var(--color-surface);
    border: 1px solid var(--border-200);
    border-radius: tokens.$radius-md;
    cursor: pointer;
    color: var(--text-600);
    transition:
      background-color tokens.$transition-fast ease,
      color tokens.$transition-fast ease,
      border-color tokens.$transition-fast ease;
    z-index: 1;

    &:hover {
      background: var(--color-surface-hover);
      color: var(--color-text-primary);
      border-color: var(--color-text-primary);
    }

    &:focus-visible {
      outline: 2px solid var(--color-accent);
      outline-offset: 1px;
    }

    &:disabled {
      opacity: 0.4;
      cursor: default;
      pointer-events: none;
    }

    svg {
      flex-shrink: 0;
    }
  }

  &__char-count {
    font-size: tokens.$font-xs;
    color: var(--text-400);
    padding: 0 tokens.$space-3 tokens.$space-2;
    text-align: right;
  }

  &__history-section {
    padding: tokens.$space-2 tokens.$space-3 0;
    border-top: 1px solid var(--border-100);
  }

  &__history-title {
    font-size: tokens.$font-xs;
    font-weight: tokens.$font-weight-medium;
    color: var(--text-600);
    margin-bottom: tokens.$space-1;
  }
}

