    },
    pt: {
      hello: 'olá',
      world: 'mundo',
      the: 'o',
      is: 'é',
      a: 'um',
      and: 'e',
      good: 'bom',
      morning: 'manhã',
      night: 'noite',
      thank: 'obrigado',
      you: 'você',
      yes: 'sim',
      no: 'não',
      please: 'por favor',
      sorry: 'desculpe',
      love: 'amor',
      water: 'água',
      food: 'comida',
      time: 'tempo',
      day: 'dia',
    },
    ja: {
      hello: 'こんにちは',
      world: '世界',
      the: '',
      is: 'です',
      a: '',
      and: 'と',
      good: '良い',
      morning: '朝',
      night: '夜',
      thank: 'ありがとう',
      you: 'あなた',
      yes: 'はい',
      no: 'いいえ',
    },
    it: {
      hello: 'ciao',
      world: 'mondo',
      the: 'il',
      is: 'è',
      a: 'un',
      and: 'e',
      good: 'buono',
      morning: 'mattina',
      night: 'notte',
      thank: 'grazie',
      you: 'tu',
      yes: 'sì',
      no: 'no',
    },
  };

  const dict = words[targetLang];
  if (!dict) return `[${targetLang}] ${text}`;

  return text
    .split(/(\s+)/)
    .map(token => {
      const lower = token.toLowerCase();
      const replacement = dict[lower];
      if (replacement !== undefined) {
        if (token[0] === token[0]?.toUpperCase() && replacement.length > 0) {
          return replacement[0]!.toUpperCase() + replacement.slice(1);
        }
        return replacement;
      }
      return token;
    })
    .join('');
}

function detectLanguage(text: string): string {
  const trimmed = text.trim();
  if (!trimmed) return 'en';

  if (/[\u3040-\u309F\u30A0-\u30FF]/.test(trimmed)) return 'ja';
  if (/[\uAC00-\uD7AF]/.test(trimmed)) return 'ko';
  if (/[\u4E00-\u9FFF]/.test(trimmed)) return 'zh';
  if (/[\u0400-\u04FF]/.test(trimmed)) return 'ru';
  if (/[\u0600-\u06FF]/.test(trimmed)) return 'ar';
  if (/[\u0900-\u097F]/.test(trimmed)) return 'hi';
  if (/[\u0E00-\u0E7F]/.test(trimmed)) return 'th';

  const spanishPatterns = /\b(el|la|los|las|de|en|que|es|un|una|con|por|para)\b/i;
  const frenchPatterns = /\b(le|la|les|des|un|une|est|et|en|que|dans|pour)\b/i;
  const germanPatterns = /\b(der|die|das|ein|eine|und|ist|von|mit|auf|für)\b/i;
  const portuguesePatterns = /\b(o|a|os|as|de|em|que|é|um|uma|com|para)\b/i;

  const scores: { lang: string; count: number }[] = [
    { lang: 'es', count: (trimmed.match(spanishPatterns) || []).length },
    { lang: 'fr', count: (trimmed.match(frenchPatterns) || []).length },
    { lang: 'de', count: (trimmed.match(germanPatterns) || []).length },
    { lang: 'pt', count: (trimmed.match(portuguesePatterns) || []).length },
  ];

  const best = scores.sort((a, b) => b.count - a.count)[0];
  if (best.count > 0) return best.lang;

  return 'en';
}

export function mockTranslate(
  text: string,
  sourceLang: string,
  targetLang: string,
): { translated: string; detectedLang?: string } {
  if (!text.trim()) return { translated: '' };

  let effectiveSource = sourceLang;
  let detectedLang: string | undefined;

  if (sourceLang === 'auto') {
    effectiveSource = detectLanguage(text);
    detectedLang = effectiveSource;
  }

  if (effectiveSource === targetLang) {
    return { translated: text, detectedLang };
  }

  const knownTranslation = MOCK_TRANSLATIONS[effectiveSource]?.[targetLang];
  if (
    knownTranslation &&
    text.trim().toLowerCase() === 'hello, how are you?'
  ) {
    return { translated: knownTranslation, detectedLang };
  }

  const swapped = simpleWordSwap(text, targetLang);
  if (swapped !== `[${targetLang}] ${text}`) {
    return { translated: swapped, detectedLang };
  }

  return { translated: swapped, detectedLang };
}

